/**
 * INSPIRE-HEP Citation Summary
 * Fetches publication data from INSPIRE-HEP API and displays citation statistics
 */

(function() {
  'use strict';

  // Configuration
  const CACHE_KEY_PREFIX = 'inspire_citations_cache_v8';
  const CACHE_DURATION = 24 * 60 * 60 * 1000; // 24 hours in milliseconds
  const API_BASE = 'https://inspirehep.net/api/literature';
  const DEFAULT_AUTHOR_BAI = 'Lu.Meng.1';
  const DEFAULT_AUTHOR_ID = '1692520';

  // Translation labels
  const TRANSLATIONS = {
    en: {
      papers: 'Papers',
      citations: 'Citations',
      citationsPerPaper: 'Cites/Paper',
      hindex: 'h-index',
      highlyCited: 'Cited >100 ',
      topJournals: 'Top Journals',
      prl: 'PRL',
      prd: 'PRD',
      physRept: 'Phys.Rept.',
      sciBull: 'Sci.Bull.',
      jhep: 'JHEP',
      dataSource: 'Data from',
      inspireLink: 'INSPIREHEP',
      lastUpdated: 'Updated',
      refresh: 'Refresh',
      loading: 'Loading citation data...',
      errorMsg: 'Unable to load citation data. Please visit the full publication list.',
      retry: 'Retry',
      citable: 'Citable',
      published: 'Published',
      citationsPerYear: 'Citations per Year',
      googleScholar: 'Google Scholar'
    },
    zh: {
      papers: '论文',
      citations: '引用',
      citationsPerPaper: '篇均引用',
      hindex: 'h指数',
      highlyCited: '引用>100',
      topJournals: '顶级期刊',
      prl: 'PRL',
      prd: 'PRD',
      physRept: 'Phys.Rept.',
      sciBull: 'Sci.Bull.',
      jhep: 'JHEP',
      dataSource: '数据来自',
      inspireLink: 'INSPIREHEP',
      lastUpdated: '更新',
      refresh: '刷新',
      loading: '正在加载引用数据...',
      errorMsg: '无法加载引用数据，请访问完整论文列表。',
      retry: '重试',
      citable: '可引用',
      published: '已发表',
      citationsPerYear: '年度引用',
      googleScholar: 'Google Scholar'
    }
  };

  // Track current mode per container
  const containerModes = new WeakMap();

  /**
   * Read citation configuration from the container.
   */
  function getCitationConfig(container) {
    const authorId = container.getAttribute('data-author-id') || DEFAULT_AUTHOR_ID;
    const authorBai = container.getAttribute('data-author-bai') || DEFAULT_AUTHOR_BAI;
    const authorUrl = container.getAttribute('data-author-url') ||
      `https://inspirehep.net/authors/${authorId}`;

    return {
      authorId: authorId,
      authorBai: authorBai,
      authorUrl: authorUrl,
      cacheKey: `${CACHE_KEY_PREFIX}_${authorBai}`
    };
  }

  /**
   * Format number with thousand separators
   */
  function formatNumber(num) {
    return num.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ',');
  }

  /**
   * Format decimal number
   */
  function formatDecimal(num, decimals = 1) {
    if (num === undefined || num === null || isNaN(num)) {
      return '0.0';
    }
    return num.toFixed(decimals);
  }

  /**
   * Format date based on language
   */
  function formatDate(date, lang) {
    const options = { year: 'numeric', month: 'short', day: 'numeric' };
    try {
      return date.toLocaleDateString(lang === 'zh' ? 'zh-CN' : 'en-US', options);
    } catch (e) {
      return date.toLocaleDateString('en-US', options);
    }
  }

  /**
   * Render a year-by-year citation histogram as a horizontal bar chart.
   */
  function renderHistogram(citationsByYear, lang) {
    if (!citationsByYear || citationsByYear.length === 0) {
      return '';
    }

    const maxCount = Math.max(...citationsByYear.map(d => d.citations), 1);
    const t = TRANSLATIONS[lang] || TRANSLATIONS.en;

    let bars = '';
    citationsByYear.forEach(function(item) {
      const heightPercent = (item.citations / maxCount) * 100;
      const barHeight = Math.max(heightPercent, 3);
      bars += `
        <div class="histogram-bar-container">
          <span class="histogram-count">${item.citations}</span>
          <div class="histogram-bar-wrapper">
            <div class="histogram-bar" style="height: ${barHeight}%;" title="${item.year}: ${item.citations} citations"></div>
          </div>
          <span class="histogram-year">${item.year}</span>
        </div>`;
    });

    return `
      <div class="citations-histogram">
        <div class="histogram-header">
          <span class="histogram-title">${t.citationsPerYear}</span>
          <a href="https://scholar.google.com/citations?user=${getCitationConfig(document.querySelector('#inspire-citations')).authorId}" target="_blank" rel="noopener noreferrer" class="histogram-source">${t.googleScholar}</a>
        </div>
        <div class="histogram-chart">
          ${bars}
        </div>
      </div>`;
  }

  /**
   * Build a "citable" or "published" search query for the given author.
   */
  function buildQuery(type, authorBai) {
    const baseQuery = `q=a ${authorBai}`;
    if (type === 'citable') {
      // "citable" => all citable papers
      return `${baseQuery}&size=100&sort=mostrecent`;
    } else if (type === 'published') {
      // "published" => only published/refereed papers — i.e. with a publication info
      return `${baseQuery}&size=100&sort=mostrecent`;
    }
    return `${baseQuery}&size=100&sort=mostrecent`;
  }

  /**
   * Check if a record has publication info (i.e. is published/refereed).
   * A record is considered published if it has at least one `publication_info`
   * entry with a `journal_title`.
   */
  function isPublished(record) {
    const pubInfo = record.metadata && record.metadata.publication_info;
    if (!pubInfo || pubInfo.length === 0) return false;
    // Some records have publication_info but no journal title — treat those as unpublished
    return pubInfo.some(function(pi) {
      return pi.journal_title && pi.journal_title.trim() !== '';
    });
  }

  /**
   * Determine if a paper should be counted as PRL/PRD/Phys.Rept./Sci.Bull./JHEP
   */
  function getTopJournalType(record) {
    const pubInfo = record.metadata && record.metadata.publication_info;
    if (!pubInfo) return null;
    // Check each publication_info entry
    for (let i = 0; i < pubInfo.length; i++) {
      const pi = pubInfo[i];
      if (!pi.journal_title) continue;
      const jt = pi.journal_title.trim();
      if (jt === 'Phys.Rev.Lett.' || jt === 'Phys. Rev. Lett.' || jt.startsWith('Phys. Rev. Lett')) {
        return 'prl';
      }
      if (jt === 'Phys.Rev.D' || jt === 'Phys. Rev. D' || jt.startsWith('Phys. Rev. D')) {
        return 'prd';
      }
      if (jt === 'Phys.Rept.' || jt === 'Phys. Rep.' || jt.startsWith('Phys. Rept')) {
        return 'physRept';
      }
      if (jt === 'Sci.Bull.' || jt === 'Sci. Bull.' || jt.startsWith('Sci. Bull')) {
        return 'sciBull';
      }
      if (jt === 'JHEP' || jt === 'J. High Energy Phys.' || jt.startsWith('JHEP')) {
        return 'jhep';
      }
    }
    return null;
  }

  /**
   * Fetch publications from INSPIRE-HEP API
   */
  async function fetchPublications(type, authorBai) {
    const query = buildQuery(type, authorBai);
    const url = `${API_BASE}?${query}`;
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }
    const data = await response.json();

    // For 'published' mode, filter only published/refereed records.
    let records = data.hits && data.hits.hits ? data.hits.hits : [];
    if (type === 'published') {
      records = records.filter(function(record) {
        return isPublished(record);
      });
    }
    return records;
  }

  /**
   * Extract citation count from a record's citation summary
   */
  function getCitationCount(record) {
    const metadata = record.metadata;
    if (metadata && metadata.citation_count !== undefined && metadata.citation_count !== null) {
      return metadata.citation_count;
    }
    // Fallback
    return 0;
  }

  /**
   * Calculate metrics from a list of publication records
   */
  function calculateMetricsFromPublications(records) {
    const totalPapers = records.length;
    let totalCitations = 0;
    const citationCounts = [];
    let highlyCitedCount = 0;
    const topJournals = { prl: 0, prd: 0, physRept: 0, sciBull: 0, jhep: 0 };

    records.forEach(function(record) {
      const citations = getCitationCount(record);
      totalCitations += citations;
      citationCounts.push(citations);

      if (citations > 100) {
        highlyCitedCount++;
      }

      const journalType = getTopJournalType(record);
      if (journalType && topJournals.hasOwnProperty(journalType)) {
        topJournals[journalType]++;
      }
    });

    const citationsPerPaper = totalPapers > 0 ? totalCitations / totalPapers : 0;

    /**
     * Calculate h-index
     */
    function calculateHIndex(counts) {
      const sorted = counts.slice().sort((a, b) => b - a);
      let h = 0;
      for (let i = 0; i < sorted.length; i++) {
        if (sorted[i] >= i + 1) {
          h = i + 1;
        } else {
          break;
        }
      }
      return h;
    }

    return {
      totalPapers: totalPapers,
      totalCitations: totalCitations,
      citationsPerPaper: citationsPerPaper,
      hIndex: calculateHIndex(citationCounts),
      highlyCitedCount: highlyCitedCount,
      topJournals: topJournals
    };
  }

  /**
   * Fetch and calculate metrics for both modes
   */
  async function fetchAllMetrics(authorBai) {
    // Fetch both citable and published papers in parallel
    const [citablePubs, publishedPubs] = await Promise.all([
      fetchPublications('citable', authorBai),
      fetchPublications('published', authorBai)
    ]);

    return {
      citable: calculateMetricsFromPublications(citablePubs),
      published: calculateMetricsFromPublications(publishedPubs),
      timestamp: Date.now()
    };
  }

  /**
   * Get cached data if still valid
   */
  function getCachedData(cacheKey, allowExpired) {
    try {
      const cached = localStorage.getItem(cacheKey);
      if (!cached) return null;

      const data = JSON.parse(cached);
      const age = Date.now() - data.timestamp;

      if (allowExpired || age < CACHE_DURATION) {
        return data;
      }
    } catch (e) {
      console.error('Error reading cache:', e);
    }
    return null;
  }

  /**
   * Save data to cache
   */
  function setCachedData(cacheKey, data) {
    try {
      localStorage.setItem(cacheKey, JSON.stringify(data));
    } catch (e) {
      console.error('Error writing cache:', e);
    }
  }

  /**
   * Render citation summary HTML
   */
  function renderSummary(metrics, lang, container, mode) {
    const t = TRANSLATIONS[lang] || TRANSLATIONS.en;
    const config = getCitationConfig(container);
    const updateDate = formatDate(new Date(metrics.timestamp), lang);

    // Get metrics for current mode
    const modeMetrics = metrics[mode] || metrics.citable || metrics;

    // Provide defaults for backward compatibility with old cached data
    const citationsPerPaper = modeMetrics.citationsPerPaper || 0;
    const topJournals = modeMetrics.topJournals || { prl: 0, prd: 0, physRept: 0, sciBull: 0, jhep: 0 };

    // Parse citations by year data from container attribute
    let citationsByYear = null;
    const citationsByYearAttr = container.getAttribute('data-citations-by-year');
    if (citationsByYearAttr) {
      try {
        citationsByYear = JSON.parse(citationsByYearAttr);
      } catch (e) {
        console.error('[INSPIRE Citations] Error parsing citations by year:', e);
      }
    }

    // Generate histogram HTML if data available
    const histogramHtml = renderHistogram(citationsByYear, lang);

    const html = `
      <div class="citations-summary">
        <div class="citations-mode-switch">
          <button class="mode-btn ${mode === 'citable' ? 'active' : ''}" data-mode="citable">${t.citable}</button>
          <button class="mode-btn ${mode === 'published' ? 'active' : ''}" data-mode="published">${t.published}</button>
        </div>
        <div class="citations-grid">
          <div class="citation-stat">
            <span class="stat-value">${formatNumber(modeMetrics.totalPapers)}</span>
            <span class="stat-label">${t.papers}</span>
          </div>
          <div class="citation-stat">
            <span class="stat-value">${formatNumber(modeMetrics.totalCitations)}</span>
            <span class="stat-label">${t.citations}</span>
          </div>
          <div class="citation-stat">
            <span class="stat-value">${formatDecimal(citationsPerPaper)}</span>
            <span class="stat-label">${t.citationsPerPaper}</span>
          </div>
          <div class="citation-stat">
            <span class="stat-value">${modeMetrics.hIndex}</span>
            <span class="stat-label">${t.hindex}</span>
          </div>
          <div class="citation-stat">
            <span class="stat-value">${formatNumber(modeMetrics.highlyCitedCount)}</span>
            <span class="stat-label">${t.highlyCited}</span>
          </div>
          <div class="citation-stat citation-stat-journals">
            <span class="stat-label">${t.topJournals}</span>
            <div class="journal-counts">
              <span class="journal-item">${t.prl}: ${topJournals.prl}</span>
              <span class="journal-item">${t.prd}: ${topJournals.prd}</span>
              <span class="journal-item">${t.physRept}: ${topJournals.physRept}</span>
              <span class="journal-item">${t.sciBull}: ${topJournals.sciBull}</span>
              <span class="journal-item">${t.jhep}: ${topJournals.jhep}</span>
            </div>
          </div>
        </div>
        ${histogramHtml}
        <div class="citations-footer">
          <small>${t.dataSource} <a href="${config.authorUrl}" target="_blank" rel="noopener noreferrer">${t.inspireLink}</a> | ${t.lastUpdated}: ${updateDate}</small>
          <br>
          <small><a href="#" class="citations-refresh">${t.refresh}</a></small>
        </div>
      </div>
    `;

    container.innerHTML = html;

    // Attach mode switch event listeners
    const modeBtns = container.querySelectorAll('.mode-btn');
    modeBtns.forEach(function(btn) {
      btn.addEventListener('click', function(e) {
        const newMode = btn.getAttribute('data-mode');
        if (newMode !== mode) {
          containerModes.set(container, newMode);
          renderSummary(metrics, lang, container, newMode);
        }
      });
    });

    // Attach refresh event listener
    const refreshLink = container.querySelector('.citations-refresh');
    if (refreshLink) {
      refreshLink.addEventListener('click', function(e) {
        e.preventDefault();
        loadCitations(container, true);
      });
    }
  }

  /**
   * Render loading state
   */
  function renderLoading(lang, container) {
    const t = TRANSLATIONS[lang] || TRANSLATIONS.en;
    container.innerHTML = `
      <div class="citations-loading">
        <span class="loading-spinner"></span>
        ${t.loading}
      </div>
    `;
  }

  /**
   * Render error state
   */
  function renderError(lang, container) {
    const t = TRANSLATIONS[lang] || TRANSLATIONS.en;
    const config = getCitationConfig(container);
    container.innerHTML = `
      <div class="citations-error">
        <p>${t.errorMsg}</p>
        <small><a href="${config.authorUrl}" target="_blank" rel="noopener noreferrer">${t.inspireLink}</a></small>
        <br>
        <small><a href="#" class="citations-retry">${t.retry}</a></small>
      </div>
    `;

    const retryLink = container.querySelector('.citations-retry');
    if (retryLink) {
      retryLink.addEventListener('click', function(e) {
        e.preventDefault();
        loadCitations(container, true);
      });
    }
  }

  /**
   * Main function to load and display citations
   */
  async function loadCitations(container, forceRefresh) {
    const lang = container.getAttribute('data-lang') || 'en';
    const defaultMode = container.getAttribute('data-mode') || 'citable';
    const config = getCitationConfig(container);

    // Get current mode or use default
    let mode = containerModes.get(container) || defaultMode;
    containerModes.set(container, mode);

    // Try to use cached data first (unless forcing refresh)
    if (!forceRefresh) {
      const cached = getCachedData(config.cacheKey, false);
      if (cached) {
        renderSummary(cached, lang, container, mode);
        return;
      }
    }

    // Show loading state
    renderLoading(lang, container);

    try {
      // Fetch fresh data from API for both modes
      const metrics = await fetchAllMetrics(config.authorBai);

      // Cache the results
      setCachedData(config.cacheKey, metrics);

      // Render the summary
      renderSummary(metrics, lang, container, mode);
    } catch (error) {
      console.error('Error fetching citations:', error);

      // Try stale cache as fallback when the API is unreachable.
      const staleCache = getCachedData(config.cacheKey, true);
      if (staleCache) {
        renderSummary(staleCache, lang, container, mode);
      } else {
        renderError(lang, container);
      }
    }
  }

  /**
   * Initialize citation containers on page load
   */
  function initCitations() {
    const containers = document.querySelectorAll('#inspire-citations');
    containers.forEach(function(container) {
      loadCitations(container, false);
    });
  }

  // Initialize when DOM is ready
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initCitations);
  } else {
    initCitations();
  }

})();

/* ==========================================================================
   INSPIRE-HEP Citation Summary Styles
   ========================================================================== */

.citations-summary,
.citations-loading,
.citations-error {
  margin: 1em 0;
}

/* Mode Switch Toggle */
.citations-mode-switch {
  display: flex;
  justify-content: center;
  gap: 0;
  margin-bottom: 1rem;
}

.mode-btn {
  padding: 0.4rem 1rem;
  font-size: 0.85em;
  font-weight: 500;
  border: 1px solid var(--global-border-color);
  background-color: var(--global-bg-color);
  color: var(--global-text-color-light);
  cursor: pointer;
  transition: all 0.2s ease;

  &:first-child {
    border-radius: 4px 0 0 4px;
    border-right: none;
  }

  &:last-child {
    border-radius: 0 4px 4px 0;
  }

  &:hover:not(.active) {
    background-color: var(--global-bg-color);
    color: var(--global-text-color);
  }

  &.active {
    background-color: var(--global-link-color);
    border-color: var(--global-link-color);
    color: #fff;
  }
}

/* Citation Grid Layout */
.citations-grid {
  display: grid;
  grid-template-columns: repeat(5, 1fr);
  gap: 0.75rem;
  margin-bottom: 0.75rem;

  @media (max-width: 768px) {
    grid-template-columns: repeat(3, 1fr);
    gap: 0.5rem;
  }

  @media (max-width: 480px) {
    grid-template-columns: repeat(2, 1fr);
    gap: 0.5rem;
  }
}

/* Individual Citation Stat */
.citation-stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  padding: 0.75rem 0.5rem;
  background-color: var(--global-bg-color);
  border: 1px solid var(--global-border-color);
  border-radius: 6px;
  transition: transform 0.2s ease, box-shadow 0.2s ease;

  &:hover {
    transform: translateY(-2px);
    box-shadow: 0 3px 6px rgba(0, 0, 0, 0.08);
  }
}

.stat-value {
  display: block;
  font-size: 1.75em;
  font-weight: 700;
  color: var(--global-link-color);
  line-height: 1.1;
  margin-bottom: 0.25rem;

  @media (max-width: 768px) {
    font-size: 1.5em;
  }

  @media (max-width: 480px) {
    font-size: 1.35em;
  }
}

.stat-label {
  display: block;
  font-size: 0.75em;
  color: var(--global-text-color-light);
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  line-height: 1.3;

  @media (max-width: 480px) {
    font-size: 0.7em;
  }
}

/* Journal Statistics Box */
.citation-stat-journals {
  grid-column: 1 / -1;
  flex-direction: row;
  justify-content: space-between;
  align-items: center;
  padding: 0.65rem 1rem;

  @media (max-width: 480px) {
    flex-direction: column;
    gap: 0.5rem;
  }

  .stat-label {
    font-size: 0.85em;
    margin-right: 1rem;
    flex-shrink: 0;

    @media (max-width: 480px) {
      margin-right: 0;
      margin-bottom: 0.25rem;
    }
  }

  .journal-counts {
    display: flex;
    gap: 1.5rem;
    flex-wrap: wrap;
    justify-content: center;

    @media (max-width: 768px) {
      gap: 1rem;
    }

    @media (max-width: 480px) {
      gap: 0.75rem;
      font-size: 0.9em;
    }
  }

  .journal-item {
    font-size: 0.875em;
    color: var(--global-text-color);
    font-weight: 500;
    white-space: nowrap;

    @media (max-width: 480px) {
      font-size: 0.8em;
    }
  }
}

/* Citations Per Year Histogram */
.citations-histogram {
  margin: 1rem 0;
  padding: 1rem;
  background-color: var(--global-bg-color);
  border: 1px solid var(--global-border-color);
  border-radius: 6px;
}

.histogram-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 0.75rem;
  padding: 0 0.25rem;
}

.histogram-title {
  font-size: 0.85em;
  font-weight: 500;
  color: var(--global-text-color-light);
  text-transform: uppercase;
  letter-spacing: 0.3px;
}

.histogram-source {
  font-size: 0.75em;
  color: var(--global-text-color-light);
  font-style: italic;
}

.histogram-chart {
  display: flex;
  justify-content: space-around;
  gap: 0.5rem;
  padding: 0 0.5rem;

  @media (max-width: 480px) {
    gap: 0.25rem;
    padding: 0;
  }
}

.histogram-bar-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  flex: 1;
  max-width: 70px;

  @media (max-width: 480px) {
    max-width: 45px;
  }
}

.histogram-count {
  font-size: 0.7em;
  font-weight: 600;
  color: var(--global-text-color);
  margin-bottom: 0.25rem;
  white-space: nowrap;
  height: 1.2em;
  line-height: 1.2em;

  @media (max-width: 480px) {
    font-size: 0.6em;
  }
}

.histogram-bar-wrapper {
  width: 100%;
  height: 80px;
  display: flex;
  align-items: flex-end;

  @media (max-width: 480px) {
    height: 60px;
  }
}

.histogram-bar {
  width: 100%;
  min-height: 4px;
  background: var(--global-link-color);
  border-radius: 3px 3px 0 0;
  transition: all 0.3s ease;

  &:hover {
    filter: brightness(1.1);
  }
}

.histogram-year {
  font-size: 0.75em;
  color: var(--global-text-color-light);
  margin-top: 0.4rem;
  font-weight: 500;
  height: 1.2em;
  line-height: 1.2em;

  @media (max-width: 480px) {
    font-size: 0.65em;
    margin-top: 0.25rem;
  }
}

/* Citations Footer */
.citations-footer {
  text-align: center;
  padding-top: 0.4rem;
  border-top: 1px solid var(--global-border-color);
  color: var(--global-text-color-light);

  small {
    font-size: 0.8em;
  }

  a.citations-refresh {
    color: var(--global-link-color);
    text-decoration: none;
    border-bottom: 1px dotted var(--global-link-color);

    &:hover {
      color: var(--global-link-color-hover);
      border-bottom-color: var(--global-link-color-hover);
    }
  }
}

/* Loading State */
.citations-loading {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 1.5rem;
  color: var(--global-text-color-light);
  font-style: italic;
  font-size: 0.9em;
}

.loading-spinner {
  display: inline-block;
  width: 14px;
  height: 14px;
  margin-right: 0.5rem;
  border: 2px solid var(--global-border-color);
  border-top-color: var(--global-link-color);
  border-radius: 50%;
  animation: spinner-rotate 0.8s linear infinite;
}

@keyframes spinner-rotate {
  to {
    transform: rotate(360deg);
  }
}

/* Error State */
.citations-error {
  padding: 1.25rem;
  background-color: lighten($danger-color, 45%);
  border: 1px solid lighten($danger-color, 30%);
  border-radius: 6px;
  text-align: center;
  font-size: 0.9em;

  p {
    margin: 0 0 0.5rem 0;
    color: darken($danger-color, 10%);
  }

  small {
    font-size: 0.875em;
  }

  a.citations-retry {
    color: $danger-color;
    text-decoration: none;
    border-bottom: 1px dotted $danger-color;

    &:hover {
      color: darken($danger-color, 10%);
      border-bottom-color: darken($danger-color, 10%);
    }
  }
}

